import{_ as r,S as s,n as u,p as c,q as t,J as a,C as i,A as n,a2 as l}from"./framework-c4fdf794.js";const h={},m={class:"table-of-contents"},v={class:"warning custom-block"};function g(p,e){const o=s("router-link"),d=s("RouterLink");return u(),c("div",null,[e[15]||(e[15]=t("h1",{id:"under-attack-mode-uam",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#under-attack-mode-uam","aria-hidden":"true"},"#"),a(" Under Attack Mode (UAM)")],-1)),t("nav",m,[t("ul",null,[t("li",null,[i(o,{to:"#overview"},{default:n(()=>[...e[0]||(e[0]=[a("Overview",-1)])]),_:1})]),t("li",null,[i(o,{to:"#how-it-works"},{default:n(()=>[...e[1]||(e[1]=[a("How it works",-1)])]),_:1})]),t("li",null,[i(o,{to:"#prerequisites"},{default:n(()=>[...e[2]||(e[2]=[a("Prerequisites",-1)])]),_:1})]),t("li",null,[i(o,{to:"#enabling-and-disabling-uam"},{default:n(()=>[...e[3]||(e[3]=[a("Enabling and disabling UAM",-1)])]),_:1})]),t("li",null,[i(o,{to:"#managing-rules"},{default:n(()=>[...e[4]||(e[4]=[a("Managing rules",-1)])]),_:1})]),t("li",null,[i(o,{to:"#path-scoping"},{default:n(()=>[...e[5]||(e[5]=[a("Path scoping",-1)])]),_:1})]),t("li",null,[i(o,{to:"#monitoring-challenges"},{default:n(()=>[...e[6]||(e[6]=[a("Monitoring challenges",-1)])]),_:1})])])]),e[16]||(e[16]=l('<h2 id="overview" tabindex="-1"><a class="header-anchor" href="#overview" aria-hidden="true">#</a> Overview</h2><p><strong>Under Attack Mode (UAM)</strong> is a WebShield feature that lets a server administrator put one or more <strong>domains</strong> (optionally scoped to specific URL paths) &quot;under attack&quot;. While a domain is under attack, every matching HTTP request is first served a lightweight <strong>JavaScript splash challenge</strong> instead of being passed straight to the site:</p><ul><li>Regular browsers solve the challenge transparently and receive a short-lived cookie; subsequent requests carrying a valid cookie flow through normally.</li><li>Simple bots that cannot run the challenge never reach the application.</li></ul><p>UAM is a <strong>server-wide administrator feature</strong>. It is distinct from the per-IP GreyList / Anti-bot Challenge: UAM decisions are keyed on the request&#39;s <code>(domain, path)</code> and are configured explicitly by the administrator, rather than being driven by the state of an IP list.</p><div class="tip custom-block"><p class="custom-block-title">When to use it</p><p>Turn UAM on for a specific domain when it is the target of an automated flood (for example scripted checkout or login abuse during a sale) and you want to gate <strong>all</strong> visitors of that domain behind a challenge, regardless of their IP reputation.</p></div>',5)),t("div",v,[e[14]||(e[14]=t("p",{class:"custom-block-title"},"Availability depends on the environment",-1)),t("p",null,[e[8]||(e[8]=a("UAM is not available on every environment WebShield supports. Before relying on it, check whether the current server supports UAM by running ",-1)),e[9]||(e[9]=t("span",{class:"notranslate"},[t("code",null,"imunify360-wsctl filters")],-1)),e[10]||(e[10]=a(" and confirming the ",-1)),e[11]||(e[11]=t("span",{class:"notranslate"},[t("code",null,"uam")],-1)),e[12]||(e[12]=a(" filter is listed as available — see ",-1)),i(d,{to:"/command_line_interface/#webshield-feature-availability"},{default:n(()=>[...e[7]||(e[7]=[a("WebShield feature availability",-1)])]),_:1}),e[13]||(e[13]=a(". Where UAM is unavailable, only the GreyList / Anti-bot Challenge applies.",-1))])]),e[17]||(e[17]=l(`<h2 id="how-it-works" tabindex="-1"><a class="header-anchor" href="#how-it-works" aria-hidden="true">#</a> How it works</h2><ul><li>A domain is placed under attack by creating a <strong>UAM rule</strong>. A rule is a <code>(domain, optional path-set)</code> tuple.</li><li>When a request matches an <strong>active</strong> rule, WebShield returns the JS splash challenge and does not forward the request to the backend until the visitor passes.</li><li>UAM is <strong>fail-open</strong>: if the feature is disabled, the request has no <code>Host</code>, the rule store cannot be read, or no active rule matches, the request simply proceeds through the normal WebShield flow. UAM never blocks a request outright — it only inserts a challenge.</li><li>The feature is gated behind a single on/off toggle that is <strong>off by default</strong>, and all UAM state is stored on the server itself.</li></ul><h2 id="prerequisites" tabindex="-1"><a class="header-anchor" href="#prerequisites" aria-hidden="true">#</a> Prerequisites</h2><ul><li>WebShield version &gt;= 1.44.2 installed and running in an environment where UAM is available (see the note above).</li><li>Root access to the server. UAM is managed with the <span class="notranslate"><code>imunify360-wsctl uam</code></span> command, which must be run as <code>root</code>.</li></ul><h2 id="enabling-and-disabling-uam" tabindex="-1"><a class="header-anchor" href="#enabling-and-disabling-uam" aria-hidden="true">#</a> Enabling and disabling UAM</h2><p>UAM is <strong>off by default</strong>. Enable the feature before creating rules — while it is disabled, all rule and counter commands fail with a <code>service_disabled</code> error.</p><div class="notranslate"><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>imunify360-wsctl uam settings service            # show the current {enabled} state
imunify360-wsctl uam settings service enable      # turn UAM on, server-wide
imunify360-wsctl uam settings service disable     # turn UAM off
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></div><p>Disabling the feature stops all challenges immediately; your rules are preserved and take effect again when you re-enable it.</p><h2 id="managing-rules" tabindex="-1"><a class="header-anchor" href="#managing-rules" aria-hidden="true">#</a> Managing rules</h2><p>A rule is created from a small JSON payload. Only <code>domain</code> is required; <code>label</code> (a free-text note) and <code>paths</code> (path scoping) are optional. A new rule is active as soon as it is created.</p><div class="notranslate"><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># Put a whole domain under attack:
imunify360-wsctl uam add &#39;{&quot;domain&quot;:&quot;shop.example.com&quot;,&quot;label&quot;:&quot;Black Friday&quot;}&#39;

# Scope the rule to specific paths (see &quot;Path scoping&quot; below):
imunify360-wsctl uam add &#39;{&quot;domain&quot;:&quot;shop.example.com&quot;,&quot;paths&quot;:{&quot;mode&quot;:&quot;include&quot;,&quot;matchers&quot;:[{&quot;value&quot;:&quot;/checkout&quot;,&quot;condition&quot;:&quot;prefix&quot;}]}}&#39;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></div><p>List the current rules (a table by default, <code>--json</code> for raw output, <code>--domain</code> to filter by exact domain):</p><div class="notranslate"><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>imunify360-wsctl uam list
imunify360-wsctl uam list --domain shop.example.com --json
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></div><p>The table shows <code>ID ACTIVE DOMAIN LABEL</code>. The <code>ID</code> is a positive integer assigned by WebShield when the rule is created; you use it to edit or delete the rule.</p><div class="notranslate"><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>imunify360-wsctl uam list
ID  ACTIVE  DOMAIN            LABEL
7   yes     shop.example.com  Black Friday
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></div><p>Edit a rule with a partial JSON payload — only <code>active</code>, <code>label</code>, and <code>paths</code> can be changed. Temporarily pausing a rule is done by setting <code>active</code> to <code>false</code>:</p><div class="notranslate"><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>imunify360-wsctl uam edit 7 &#39;{&quot;active&quot;:false}&#39;      # pause the rule (keep it for later)
imunify360-wsctl uam edit 7 &#39;{&quot;label&quot;:&quot;BF sale&quot;}&#39;   # rename
imunify360-wsctl uam edit 7 &#39;{&quot;paths&quot;:null}&#39;         # clear paths -&gt; back to whole-domain
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></div><p>Delete a rule by ID. Delete is idempotent — deleting an ID that no longer exists still succeeds:</p><div class="notranslate"><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>imunify360-wsctl uam delete 7
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></div><h2 id="path-scoping" tabindex="-1"><a class="header-anchor" href="#path-scoping" aria-hidden="true">#</a> Path scoping</h2><p>By default a rule covers the whole domain. Add a <code>paths</code> block to challenge only some URLs. The block has a <code>mode</code> and a list of <code>matchers</code>:</p><ul><li><code>mode: &quot;include&quot;</code> — the matchers list the paths that <strong>are</strong> under attack. A request is challenged only if it matches one of them.</li><li><code>mode: &quot;exclude&quot;</code> — the matchers list <strong>exceptions</strong>. A matching request is let through; everything else on the domain is challenged.</li></ul><p>Each matcher is <code>{&quot;value&quot;: &quot;...&quot;, &quot;condition&quot;: &quot;...&quot;}</code>, where <code>condition</code> is one of <code>equals</code>, <code>prefix</code>, <code>suffix</code>, or <code>contains</code>. A rule may hold between 1 and 32 matchers, and a request matches the block if it satisfies <strong>any</strong> of them.</p><div class="notranslate"><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># Only challenge /api and everything under /checkout:
imunify360-wsctl uam add &#39;{&quot;domain&quot;:&quot;shop.example.com&quot;,&quot;paths&quot;:{&quot;mode&quot;:&quot;include&quot;,&quot;matchers&quot;:[{&quot;value&quot;:&quot;/api&quot;,&quot;condition&quot;:&quot;equals&quot;},{&quot;value&quot;:&quot;/checkout&quot;,&quot;condition&quot;:&quot;prefix&quot;}]}}&#39;

# Challenge the whole domain EXCEPT the health-check endpoint:
imunify360-wsctl uam add &#39;{&quot;domain&quot;:&quot;shop.example.com&quot;,&quot;paths&quot;:{&quot;mode&quot;:&quot;exclude&quot;,&quot;matchers&quot;:[{&quot;value&quot;:&quot;/healthz&quot;,&quot;condition&quot;:&quot;equals&quot;}]}}&#39;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></div><h2 id="monitoring-challenges" tabindex="-1"><a class="header-anchor" href="#monitoring-challenges" aria-hidden="true">#</a> Monitoring challenges</h2><p>Each challenge served for a rule is counted. Use <code>counters</code> to see which rules are actively challenging traffic, busiest first:</p><div class="notranslate"><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>imunify360-wsctl uam counters                       # all rules with hits today, busiest first
imunify360-wsctl uam counters --since 24h           # a rolling window instead of &quot;today&quot;
imunify360-wsctl uam counters shop.example.com      # filter by exact domain
imunify360-wsctl uam counters 7                      # filter by rule id
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></div><p>The single optional argument is auto-detected: a positive integer is treated as a rule ID, anything else as an exact domain. The <code>--since</code> window is one of <code>today</code> (default), <code>1h</code>, <code>4h</code>, <code>24h</code>, <code>4d</code>, or <code>7d</code>. Output columns are <code>ID ACTIVE DOMAIN HITS LABEL</code>. Only rules with at least one challenge in the window are listed, and challenge counts are retained for 7 days.</p><div class="notranslate"><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>imunify360-wsctl uam counters
ID  ACTIVE  DOMAIN            HITS  LABEL
7   yes     shop.example.com  1523  Black Friday
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></div>`,29))])}const f=r(h,[["render",g],["__file","index.html.vue"]]);export{f as default};
